package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.AccessibleObject;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

import com.google.gson.internal.ReflectionAccessFilterHelper;

class ReflectionAccessFilterHelperTest {

  private AccessibleObject accessibleObjectMock;
  private Object targetObject;

  @BeforeEach
  void setUp() {
    accessibleObjectMock = mock(AccessibleObject.class);
    targetObject = new Object();
  }

  @Test
  void testCanAccess_returnsTrue_whenAccessCheckerReturnsTrue() {
    try (MockedStatic<ReflectionAccessFilterHelper.AccessChecker> accessCheckerStatic = Mockito.mockStatic(ReflectionAccessFilterHelper.AccessChecker.class)) {
      ReflectionAccessFilterHelper.AccessChecker accessCheckerMock = mock(ReflectionAccessFilterHelper.AccessChecker.class);
      accessCheckerStatic.when(() -> ReflectionAccessFilterHelper.AccessChecker.INSTANCE).thenReturn(accessCheckerMock);
      when(accessCheckerMock.canAccess(accessibleObjectMock, targetObject)).thenReturn(true);

      boolean result = ReflectionAccessFilterHelper.canAccess(accessibleObjectMock, targetObject);
      assertTrue(result);

      verify(accessCheckerMock).canAccess(accessibleObjectMock, targetObject);
    }
  }

  @Test
  void testCanAccess_returnsFalse_whenAccessCheckerReturnsFalse() {
    try (MockedStatic<ReflectionAccessFilterHelper.AccessChecker> accessCheckerStatic = Mockito.mockStatic(ReflectionAccessFilterHelper.AccessChecker.class)) {
      ReflectionAccessFilterHelper.AccessChecker accessCheckerMock = mock(ReflectionAccessFilterHelper.AccessChecker.class);
      accessCheckerStatic.when(() -> ReflectionAccessFilterHelper.AccessChecker.INSTANCE).thenReturn(accessCheckerMock);
      when(accessCheckerMock.canAccess(accessibleObjectMock, targetObject)).thenReturn(false);

      boolean result = ReflectionAccessFilterHelper.canAccess(accessibleObjectMock, targetObject);
      assertFalse(result);

      verify(accessCheckerMock).canAccess(accessibleObjectMock, targetObject);
    }
  }

  @Test
  void testPrivateConstructor() throws Exception {
    var constructor = ReflectionAccessFilterHelper.class.getDeclaredConstructor();
    constructor.setAccessible(true);
    Object instance = constructor.newInstance();
    assertNotNull(instance);
  }
}

